import{_ as e,o as t,c as o,Q as n}from"./chunks/framework.c4d6cd72.js";const m=JSON.parse('{"title":"Registering an account","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/registering-an-account.md","filePath":"getting-started/registering-an-account.md"}'),r={name:"getting-started/registering-an-account.md"},a=n('<h1 id="registering-an-account" tabindex="-1">Registering an account <a class="header-anchor" href="#registering-an-account" aria-label="Permalink to &quot;Registering an account&quot;">​</a></h1><p>To begin using FIB as a peer and accessing API endpoints, you need to register a user account.</p><p>To register an account, perform the following steps:</p><ol><li>Go to the <a href="https://blockchain.fraudintelligencelimited.com/#/Index" target="_blank" rel="noreferrer">Fraud Intelligence Blockchain website</a> and select <strong>Register</strong> from the top right menu.</li><li>On the <strong>User details for Registration</strong> page that appears, fill in your personal and company details.</li><li>Agree to the <a href="https://github.com/fraud-intelligence-limited/fil-legal/blob/main/Fraud%20Intelligence%20Blockchain%20Terms%20of%20Use%20v4.0.pdf" target="_blank" rel="noreferrer">Terms &amp; Conditions</a> by selecting the <strong>I agree to the terms</strong> checkbox.</li><li>On the <strong>Subscription details</strong> tab, select <strong>Register Account</strong>.</li></ol><h3 id="expected-result" tabindex="-1">Expected Result <a class="header-anchor" href="#expected-result" aria-label="Permalink to &quot;Expected Result&quot;">​</a></h3><p>You have now submitted your registration application which is then manually reviewed by the Consortium Administrator.</p><p>As soon as your application is approved, you receive an email notifying you that you become a peer in the FIB network and, depending on the chosen access method, you can access the FIB functionality via Web UI and/or API endpoints.</p><p>For Web UI tutorials, see <a href="./../tutorials-web.html">Tutorials: Web interface</a>.</p><p>For API tutorials, see <a href="./../tutorials-api.html">Tutorials: API</a>.</p><h2 id="restoring-access-to-an-account" tabindex="-1">Restoring access to an account <a class="header-anchor" href="#restoring-access-to-an-account" aria-label="Permalink to &quot;Restoring access to an account&quot;">​</a></h2><p>If you have forgotten the password on your account, you can reset it by performing the following steps:</p><ol><li>Go to the <a href="https://blockchain.fraudintelligencelimited.com/#/Index" target="_blank" rel="noreferrer">Fraud Intelligence Blockchain website</a> and select either <strong>Register</strong> or <strong>Log in</strong> in the top right menu.</li><li>On the <strong>Register</strong> or <strong>Log in</strong> page, click <strong>Forgot password?</strong></li><li>On the <strong>Enter email to reset password page</strong>, enter the email address that you registered with in the provided field, then select <strong>Reset password</strong>.</li><li>Check your email inbox for a message from the FIB with instructions on how to reset your password.</li><li>Once you have reset your password, you can log in to your FIB account using your new password.</li></ol>',12),i=[a];function s(c,l,g,h,u,d){return t(),o("div",null,i)}const f=e(r,[["render",s]]);export{m as __pageData,f as default};
